// ===== TEXT MEASUREMENT FOR LABEL SIZING =====
const measureTextWidth = (() => {
  let canvas = null;
  return (text, fontSize = 11, fontFamily = 'Segoe UI') => {
    if (typeof document === 'undefined') return text.length * fontSize * 0.6;
    if (!canvas) canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    ctx.font = `600 ${fontSize}px ${fontFamily}`;
    return ctx.measureText(text).width;
  };
})();

// ===== NESTING-AWARE SLIDE-FIT LAYOUT =====
function autoLayout(data) {
  const nds = (data.nodes||[]).filter(n=>ALL[n.type] || EXTERNAL_TYPES.has(n.type));
  const grps = data.groups||[];
  const edgeList = data.edges||[];
  const grpMap = {}; grps.forEach(g=>{ grpMap[g.id]=g; });
  const nodeW=72, nodeH=74, gGap=20;
  // Depth-based padding: deeper groups get more padding for visual clarity
  const getPadding = (depth) => ({
    padX: 20 + depth * 6,
    padY: 16 + depth * 4,
    top: 32 + depth * 2
  });

  // Separate node children and group children for each group
  const grpIds = new Set(grps.map(g=>g.id));
  const childGroups = {}; // gid -> [child group ids]
  const childNodes = {};  // gid -> [child node objects]
  const parentOf = {};    // gid -> parent gid
  grps.forEach(g=>{
    const cg = [], cn = [];
    (g.children||[]).forEach(cid=>{
      if(grpIds.has(cid)){ cg.push(cid); parentOf[cid]=g.id; }
      else { const nd = nds.find(n=>n.id===cid); if(nd) cn.push(nd); }
    });
    childGroups[g.id]=cg;
    childNodes[g.id]=cn;
  });

  // Find root groups (no parent)
  const roots = grps.filter(g=>!parentOf[g.id]);

  // Compute depth for rendering order
  const depth = {};
  function setDepth(gid, d) { depth[gid]=d; (childGroups[gid]||[]).forEach(cid=>setDepth(cid,d+1)); }
  roots.forEach(g=>setDepth(g.id, 0));

  // Size groups bottom-up (leaves first)
  const gSize = {}; // gid -> {w, h, cols, rows, pad}
  function sizeGroup(gid) {
    const d = depth[gid] || 0;
    const pad = getPadding(d);
    const cgs = childGroups[gid]||[];
    const cns = childNodes[gid]||[];
    // Size child groups first
    cgs.forEach(cid=>sizeGroup(cid));

    // Child groups laid out horizontally
    let cgW=0, cgH=0;
    cgs.forEach(cid=>{ cgW+=gSize[cid].w+gGap; cgH=Math.max(cgH, gSize[cid].h); });
    if(cgs.length) cgW-=gGap; // remove trailing gap

    // Direct nodes in a grid row below (or beside) child groups
    const nCols = cns.length<=3?cns.length:Math.min(4,cns.length);
    const nRows = Math.ceil((cns.length||0)/(nCols||1));
    const nodesW = nCols*nodeW;
    const nodesH = nRows*nodeH;

    // Total inner content
    const innerW = Math.max(cgW, nodesW);
    const innerH = (cgH>0&&nodesH>0) ? cgH+gGap+nodesH : cgH+nodesH;

    // Measure group label width to ensure container fits it
    const grp = grpMap[gid];
    const labelText = grp?.label || '';
    const labelW = measureTextWidth(labelText, d > 0 ? 10 : 11) + 24; // padding for label

    gSize[gid] = {
      w: Math.max(160, innerW + pad.padX*2, labelW),
      h: Math.max(100, innerH + pad.top + pad.padY*2),
      cgW, cgH, nCols, nRows, nodesW, nodesH, pad
    };
  }
  grps.forEach(g=>{ if(!parentOf[g.id]) sizeGroup(g.id); });

  // Position groups top-down
  const gPos = {}; // gid -> {x, y}
  const nPos = {}; // nid -> {x, y}

  function positionGroup(gid, ox, oy) {
    gPos[gid] = {x:ox, y:oy};
    const s = gSize[gid];
    const { padX, padY, top } = s.pad;
    const cgs = childGroups[gid]||[];
    const cns = childNodes[gid]||[];
    const contentX = ox + padX;
    const contentY = oy + top + padY;

    // Position child groups horizontally
    let cx = contentX + Math.max(0, (s.w-padX*2-s.cgW)/2); // center child groups
    cgs.forEach(cid=>{
      const cs = gSize[cid];
      positionGroup(cid, cx, contentY);
      cx += cs.w + gGap;
    });

    // Position direct nodes below child groups (or at top if no child groups)
    const nodeStartY = s.cgH>0 ? contentY + s.cgH + gGap : contentY;
    const nodeStartX = contentX + Math.max(0, (s.w-padX*2-s.nodesW)/2); // center nodes
    cns.forEach((n,i)=>{
      const col = i % (s.nCols||1);
      const row = Math.floor(i / (s.nCols||1));
      nPos[n.id] = {
        x: nodeStartX + nodeW/2 + col*nodeW,
        y: nodeStartY + nodeH/2 + row*nodeH
      };
    });
  }

  // Flow-sort roots using edge topology between root groups
  function rootOf(nid) {
    // Find which root group this node belongs to
    for (const g of grps) {
      if ((g.children||[]).includes(nid)) {
        let gid = g.id;
        while(parentOf[gid]) gid=parentOf[gid];
        return gid;
      }
    }
    return null;
  }
  const rootAdj={}; const rootInDeg={};
  roots.forEach(g=>{rootAdj[g.id]=new Set();rootInDeg[g.id]=0;});
  edgeList.forEach(e=>{
    const rf=rootOf(e.from), rt=rootOf(e.to);
    if(rf&&rt&&rf!==rt&&rootAdj[rf]&&!rootAdj[rf].has(rt)){
      rootAdj[rf].add(rt); rootInDeg[rt]=(rootInDeg[rt]||0)+1;
    }
  });
  // Topo sort
  const sorted=[]; const vis=new Set(); const q=roots.filter(g=>!rootInDeg[g.id]).map(g=>g.id);
  while(q.length){ const nx=[]; q.forEach(gid=>{sorted.push(gid);vis.add(gid);rootAdj[gid]?.forEach(dep=>{rootInDeg[dep]--;if(!rootInDeg[dep]&&!vis.has(dep))nx.push(dep);});}); q.length=0;q.push(...nx); }
  roots.forEach(g=>{if(!vis.has(g.id))sorted.push(g.id);});

  // Place root groups left-to-right
  let rx=30;
  const maxH = Math.max(100,...sorted.map(gid=>gSize[gid]?.h||0));
  sorted.forEach(gid=>{
    const s=gSize[gid];
    const ry = Math.max(30, (maxH-s.h)/2+30); // vertically center
    positionGroup(gid, rx, ry);
    rx += s.w + gGap*1.5;
  });

  // Ungrouped nodes
  const allGroupedNodes = new Set();
  function collectNodes(gid){ (childNodes[gid]||[]).forEach(n=>allGroupedNodes.add(n.id)); (childGroups[gid]||[]).forEach(cid=>collectNodes(cid)); }
  grps.forEach(g=>collectNodes(g.id));
  const ung = nds.filter(n=>!allGroupedNodes.has(n.id));
  if(ung.length){
    const uy = 40;
    ung.forEach((n,i)=>{ nPos[n.id]={x:rx+nodeW/2+(i%2)*nodeW, y:uy+nodeH/2+Math.floor(i/2)*nodeH}; });
  }

  // Sort groups by depth for rendering (outer first)
  const sortedGrps = [...grps].sort((a,b)=>(depth[a.id]||0)-(depth[b.id]||0));

  return {
    title:data.title,
    nodes:nds.map(n=>({id:n.id,type:n.type,label:n.label,...(n.techName?{techName:n.techName}:{}),...(n.wafPillar?{wafPillar:n.wafPillar}:{}),x:nPos[n.id]?.x??300,y:nPos[n.id]?.y??300})),
    groups:sortedGrps.filter(g=>GT[g.type]&&gPos[g.id]).map(g=>{
      const s=gSize[g.id]; const p=gPos[g.id]; const tpl=GT[g.type]||GT.rg;
      const d = depth[g.id]||0;
      return {id:g.id,type:g.type,label:g.label,x:p.x,y:p.y,w:s.w,h:s.h,
        color:tpl.color,border:tpl.border,dash:!!tpl.dash,depth:d,children:g.children||[],
        ...(g.collapsed?{collapsed:true}:{}),...(g.compliance?{compliance:g.compliance}:{})};
    }),
    edges:edgeList.map((e,i)=>({id:`e${i}`,from:e.from,to:e.to,label:e.label||"",style:e.style||"solid",bendPoints:null,...(e.classification?{classification:e.classification}:{})})),
  };
}

// ===== ELK.js LAYOUT ENGINE =====
async function elkLayout(data) {
  const nds = (data.nodes||[]).filter(n=>ALL[n.type]);
  const grps = data.groups||[];
  const edgeList = data.edges||[];
  if (!nds.length && !grps.length) return null;

  // Build parent mapping
  const parentOf = {};
  const grpIds = new Set(grps.map(g=>g.id));
  grps.forEach(g => {
    (g.children||[]).forEach(cid => {
      if (grpIds.has(cid)) parentOf[cid] = g.id;
    });
  });

  // Find root groups
  const roots = grps.filter(g => !parentOf[g.id]);

  // Recursively build ELK children
  function buildChildren(parentId) {
    const children = [];
    const group = grps.find(g => g.id === parentId);
    if (!group) return children;

    (group.children || []).forEach(cid => {
      const childGroup = grps.find(g => g.id === cid);
      if (childGroup) {
        // It's a nested group - extra top padding for edge routing clearance
        children.push({
          id: cid,
          labels: [{ text: childGroup.label || '' }],
          layoutOptions: {
            'elk.padding': '[top=50,left=25,bottom=25,right=25]',
            'elk.portConstraints': 'FIXED_SIDE'
          },
          children: buildChildren(cid)
        });
      } else {
        // It's a node
        const node = nds.find(n => n.id === cid);
        if (node) {
          children.push({
            id: node.id,
            width: 72,
            height: 90,
            labels: [{ text: node.label || '' }]
          });
        }
      }
    });
    return children;
  }

  // Build top-level children (root groups + ungrouped nodes)
  const topChildren = [];

  // Add root groups with their nested children
  roots.forEach(g => {
    topChildren.push({
      id: g.id,
      labels: [{ text: g.label || '' }],
      layoutOptions: {
        'elk.padding': '[top=60,left=30,bottom=30,right=30]',
        'elk.portConstraints': 'FIXED_SIDE'
      },
      children: buildChildren(g.id)
    });
  });

  // Find ungrouped nodes
  const groupedNodeIds = new Set();
  const collectGroupedNodes = (gid) => {
    const g = grps.find(gr => gr.id === gid);
    if (!g) return;
    (g.children || []).forEach(cid => {
      if (grpIds.has(cid)) collectGroupedNodes(cid);
      else groupedNodeIds.add(cid);
    });
  };
  grps.forEach(g => collectGroupedNodes(g.id));

  nds.filter(n => !groupedNodeIds.has(n.id)).forEach(n => {
    topChildren.push({
      id: n.id,
      width: 72,
      height: 90,
      labels: [{ text: n.label || '' }]
    });
  });

  // Build edges
  const elkEdges = edgeList.map((e, i) => ({
    id: `e${i}`,
    sources: [e.from],
    targets: [e.to],
    labels: e.label ? [{ text: e.label, width: Math.max(40, e.label.length * 7), height: 18 }] : []
  }));

  const elkGraph = {
    id: 'root',
    layoutOptions: {
      'elk.algorithm': 'layered',
      'elk.direction': 'RIGHT',
      // Node spacing
      'elk.spacing.nodeNode': '50',
      'elk.layered.spacing.nodeNodeBetweenLayers': '100',
      'elk.spacing.componentComponent': '80',
      // Edge spacing - key for avoiding overlaps
      'elk.spacing.edgeNode': '50',
      'elk.spacing.edgeEdge': '25',
      'elk.layered.spacing.edgeNodeBetweenLayers': '50',
      'elk.layered.spacing.edgeEdgeBetweenLayers': '25',
      'elk.spacing.portPort': '15',
      // Edge routing
      'elk.edgeRouting': 'ORTHOGONAL',
      'elk.layered.unnecessaryBendpoints': 'true',
      'elk.layered.mergeEdges': 'false',
      'elk.layered.feedbackEdges': 'true',
      // Hierarchy - critical for nested containers
      'elk.hierarchyHandling': 'INCLUDE_CHILDREN',
      'elk.layered.crossingMinimization.semiInteractive': 'true',
      // Node placement
      'elk.layered.nodePlacement.strategy': 'NETWORK_SIMPLEX',
      'elk.layered.crossingMinimization.strategy': 'LAYER_SWEEP',
      'elk.layered.considerModelOrder.strategy': 'NODES_AND_EDGES',
      // Compaction for tighter layout
      'elk.layered.compaction.postCompaction.strategy': 'EDGE_LENGTH',
      'elk.layered.wrapping.strategy': 'OFF',
      // High degree node handling
      'elk.layered.highDegreeNodes.treatment': 'true',
      'elk.layered.highDegreeNodes.threshold': '8',
    },
    children: topChildren,
    edges: elkEdges
  };

  try {
    const result = await elk.layout(elkGraph);

    // Extract node positions
    const nodePositions = {};
    const groupData = {};

    const extractPositions = (elkNode, offsetX = 0, offsetY = 0) => {
      const x = (elkNode.x || 0) + offsetX;
      const y = (elkNode.y || 0) + offsetY;

      if (elkNode.children && elkNode.children.length > 0) {
        // It's a group
        groupData[elkNode.id] = {
          x, y,
          w: elkNode.width || 200,
          h: elkNode.height || 150
        };
        elkNode.children.forEach(c => extractPositions(c, x, y));
      } else {
        // It's a node
        nodePositions[elkNode.id] = {
          x: x + (elkNode.width || 72) / 2,
          y: y + (elkNode.height || 90) / 2
        };
      }
    };

    (result.children || []).forEach(c => extractPositions(c, 0, 0));

    // Extract edge routing (bend points) from all sections
    const edgeRouting = {};
    (result.edges || []).forEach(e => {
      const points = [];
      // ELK may return multiple sections for edges crossing hierarchy boundaries
      (e.sections || []).forEach((section, idx) => {
        if (idx === 0 && section.startPoint) {
          points.push(section.startPoint);
        }
        if (section.bendPoints) {
          points.push(...section.bendPoints);
        }
        if (section.endPoint) {
          points.push(section.endPoint);
        }
      });
      if (points.length >= 2) {
        edgeRouting[e.id] = points;
      }
    });
    // Debug: log edge routing info (uncomment for debugging)
    // console.log('ELK edge routing:', Object.keys(edgeRouting).length, 'edges with bendPoints');

    // Post-process: bring ungrouped nodes closer to grouped content
    // ELK places ungrouped nodes too far right due to layer spacing
    let ungroupedShift = 0;
    const ungroupedNodeIdSet = new Set();
    if (Object.keys(groupData).length > 0) {
      // Find bounding box of all groups
      const groupBounds = Object.values(groupData);
      const groupMaxX = Math.max(...groupBounds.map(g => g.x + g.w));

      // Find ungrouped nodes (not in any group's children)
      nds.filter(n => !groupedNodeIds.has(n.id)).forEach(n => ungroupedNodeIdSet.add(n.id));

      if (ungroupedNodeIdSet.size > 0) {
        // Calculate where ungrouped nodes currently are
        const ungroupedPositions = [...ungroupedNodeIdSet]
          .map(id => nodePositions[id])
          .filter(p => p);

        if (ungroupedPositions.length > 0) {
          const ungroupedMinX = Math.min(...ungroupedPositions.map(p => p.x));

          // If ungrouped nodes are more than 150px from group edge, bring them closer
          const gap = ungroupedMinX - groupMaxX;
          if (gap > 150) {
            ungroupedShift = gap - 100; // Keep 100px gap
            ungroupedNodeIdSet.forEach(id => {
              if (nodePositions[id]) {
                nodePositions[id].x -= ungroupedShift;
              }
            });
            // console.log('ELK post-process: shifted ungrouped nodes by', -ungroupedShift);
          }
        }
      }
    }

    // Also shift edge bendPoints for edges targeting ungrouped nodes
    if (ungroupedShift > 0) {
      Object.keys(edgeRouting).forEach(edgeId => {
        const edgeIdx = parseInt(edgeId.replace('e', ''));
        const edge = edgeList[edgeIdx];
        if (edge && ungroupedNodeIdSet.has(edge.to)) {
          // Shift all points after the midpoint (target side)
          const pts = edgeRouting[edgeId];
          if (pts && pts.length >= 2) {
            // Shift the last point (endpoint) and any horizontal segments going to it
            const lastPt = pts[pts.length - 1];
            lastPt.x -= ungroupedShift;
            // Also shift second-to-last if it's a horizontal segment to the target
            if (pts.length >= 3) {
              const secondLast = pts[pts.length - 2];
              if (Math.abs(secondLast.y - lastPt.y) < 2) {
                // Horizontal segment to target - shift it too
                secondLast.x -= ungroupedShift;
              }
            }
          }
        }
      });
    }

    // Compute depth for each group
    const depth = {};
    const setDepth = (gid, d) => {
      depth[gid] = d;
      const g = grps.find(gr => gr.id === gid);
      if (g) {
        (g.children || []).filter(c => grpIds.has(c)).forEach(cid => setDepth(cid, d + 1));
      }
    };
    roots.forEach(g => setDepth(g.id, 0));

    return {
      title: data.title,
      nodes: nds.map(n => ({
        id: n.id, type: n.type, label: n.label,
        ...(n.techName ? { techName: n.techName } : {}),
        ...(n.wafPillar ? { wafPillar: n.wafPillar } : {}),
        x: nodePositions[n.id]?.x ?? 300,
        y: nodePositions[n.id]?.y ?? 300
      })),
      groups: grps.filter(g => GT[g.type] && groupData[g.id]).map(g => {
        const pos = groupData[g.id];
        const tpl = GT[g.type] || GT.rg;
        return {
          id: g.id, type: g.type, label: g.label,
          x: pos.x, y: pos.y, w: pos.w, h: pos.h,
          color: tpl.color, border: tpl.border, dash: !!tpl.dash,
          depth: depth[g.id] || 0, children: g.children || [],
          ...(g.collapsed ? { collapsed: true } : {}),
          ...(g.compliance ? { compliance: g.compliance } : {})
        };
      }),
      edges: edgeList.map((e, i) => ({
        id: `e${i}`, from: e.from, to: e.to,
        label: e.label || '', style: e.style || 'solid',
        bendPoints: edgeRouting[`e${i}`] || null,
        ...(e.classification ? { classification: e.classification } : {})
      }))
    };
  } catch (err) {
    console.error('ELK layout failed:', err);
    return null;
  }
}

// ===== ORTHOGONAL EDGE ROUTING (Manhattan paths with rounded corners) =====
const EDGE_CR = 8; // corner radius
const CONTAINER_CLEARANCE = 50; // clearance above containers for edge routing

// Check if a line segment intersects with a container
function segmentIntersectsContainer(p1, p2, g) {
  // For horizontal segments
  if (Math.abs(p1.y - p2.y) < 2) {
    const y = p1.y;
    const minX = Math.min(p1.x, p2.x), maxX = Math.max(p1.x, p2.x);
    return y > g.y && y < g.y + g.h && maxX > g.x && minX < g.x + g.w;
  }
  // For vertical segments
  if (Math.abs(p1.x - p2.x) < 2) {
    const x = p1.x;
    const minY = Math.min(p1.y, p2.y), maxY = Math.max(p1.y, p2.y);
    return x > g.x && x < g.x + g.w && maxY > g.y && minY < g.y + g.h;
  }
  return false;
}

// Lift bendPoints above containers they would cross through
function avoidContainers(pts, groups, sourceId, targetId) {
  // Simplified: trust ELK's routing and only do minimal adjustments
  // ELK already handles obstacle avoidance, so we just pass through the points
  // This eliminates the aggressive "fly over top" behavior
  if (!pts || pts.length < 2) return pts;

  // Find containers that this edge actually crosses through (excluding source/target containers)
  const crossedContainers = [];
  for (let i = 0; i < pts.length - 1; i++) {
    const p1 = pts[i], p2 = pts[i+1];
    groups.forEach(g => {
      // Skip containers that contain the source or target
      if (g.id === sourceId || g.id === targetId) return;
      // Also skip if source or target is a child of this group
      if (g.children && (g.children.includes(sourceId) || g.children.includes(targetId))) return;
      if (segmentIntersectsContainer(p1, p2, g) && !crossedContainers.includes(g)) {
        crossedContainers.push(g);
      }
    });
  }

  // If no unrelated containers are crossed, return original path
  if (crossedContainers.length === 0) return pts;

  // Only reroute if we're crossing through containers we shouldn't
  // Use a more conservative approach: route around the specific obstacle
  const start = pts[0], end = pts[pts.length - 1];
  const dx = end.x - start.x;
  const dy = end.y - start.y;

  // Determine if horizontal or vertical routing makes more sense
  if (Math.abs(dx) > Math.abs(dy)) {
    // Horizontal-dominant: try going around vertically
    const maxContainerBottom = Math.max(...crossedContainers.map(g => g.y + g.h));
    const minContainerTop = Math.min(...crossedContainers.map(g => g.y));

    // Check which way is shorter: over the top or under the bottom
    const goOverTop = (start.y - minContainerTop) < (maxContainerBottom - start.y);

    if (goOverTop) {
      const topY = Math.max(minContainerTop - CONTAINER_CLEARANCE, 20);
      return [
        { x: start.x, y: start.y },
        { x: start.x, y: topY },
        { x: end.x, y: topY },
        { x: end.x, y: end.y }
      ];
    } else {
      const bottomY = maxContainerBottom + CONTAINER_CLEARANCE;
      return [
        { x: start.x, y: start.y },
        { x: start.x, y: bottomY },
        { x: end.x, y: bottomY },
        { x: end.x, y: end.y }
      ];
    }
  } else {
    // Vertical-dominant: try going around horizontally
    const maxContainerRight = Math.max(...crossedContainers.map(g => g.x + g.w));
    const minContainerLeft = Math.min(...crossedContainers.map(g => g.x));

    // Check which way is shorter: around left or around right
    const goAroundLeft = (start.x - minContainerLeft) < (maxContainerRight - start.x);

    if (goAroundLeft) {
      const leftX = Math.max(minContainerLeft - CONTAINER_CLEARANCE, 20);
      return [
        { x: start.x, y: start.y },
        { x: leftX, y: start.y },
        { x: leftX, y: end.y },
        { x: end.x, y: end.y }
      ];
    } else {
      const rightX = maxContainerRight + CONTAINER_CLEARANCE;
      return [
        { x: start.x, y: start.y },
        { x: rightX, y: start.y },
        { x: rightX, y: end.y },
        { x: end.x, y: end.y }
      ];
    }
  }
}

function nodePorts(node, portOffset = 28) {
  return {
    top:    { x: node.x,           y: node.y - portOffset },
    right:  { x: node.x + portOffset, y: node.y           },
    bottom: { x: node.x,           y: node.y + portOffset },
    left:   { x: node.x - portOffset, y: node.y           },
  };
}

function groupPorts(group) {
  // Use collapsed dimensions (160x40) when group is collapsed
  const w = group.collapsed ? 160 : group.w;
  const h = group.collapsed ? 40 : group.h;
  const cx = group.x + w / 2, cy = group.y + h / 2;
  return {
    top:    { x: cx,           y: group.y     },
    right:  { x: group.x + w,  y: cy          },
    bottom: { x: cx,           y: group.y + h },
    left:   { x: group.x,      y: cy          },
  };
}

function resolveAnchor(id, nodes, groups, portOffset = 28) {
  const nd = nodes.find(n => n.id === id);
  if (nd) return { cx: nd.x, cy: nd.y, ports: nodePorts(nd, portOffset) };
  const g = groups.find(g => g.id === id);
  if (g) {
    // Use collapsed dimensions (160x40) when group is collapsed
    const w = g.collapsed ? 160 : g.w;
    const h = g.collapsed ? 40 : g.h;
    return { cx: g.x + w / 2, cy: g.y + h / 2, ports: groupPorts(g) };
  }
  return null;
}

function selectPorts(sA, tA, allGroups) {
  const dx = tA.cx - sA.cx;
  const dy = tA.cy - sA.cy;
  const absDx = Math.abs(dx);
  const absDy = Math.abs(dy);

  // Smart geometry-based port selection:
  // Use the most direct path based on relative positions

  // Horizontal-dominant: use side ports (right→left or left→right)
  if (absDx > absDy) {
    return dx > 0
      ? { srcPort: 'right', tgtPort: 'left' }   // target is to the right
      : { srcPort: 'left', tgtPort: 'right' };  // target is to the left
  }

  // Vertical-dominant: use top/bottom ports
  return dy > 0
    ? { srcPort: 'bottom', tgtPort: 'top' }     // target is below
    : { srcPort: 'top', tgtPort: 'bottom' };    // target is above
}

function orthogonalPath(srcPort, tgtPort, sp, tp) {
  const r = EDGE_CR;
  const segs = [`M ${sp.x},${sp.y}`];
  // U-shape: both ports on same side (e.g. both top → go up, across, down)
  const sameSide = srcPort === tgtPort;
  if (sameSide) {
    const clearance = 40;
    if (srcPort === 'top' || srcPort === 'bottom') {
      // Vertical U-shape: fly ABOVE all containers
      const dir = srcPort === 'top' ? -1 : 1;
      // Use a fixed high point above everything — higher when nodes are far apart
      const spread = Math.abs(tp.x - sp.x);
      const dynamicClear = clearance + Math.min(spread * 0.15, 60);
      const peakY = (srcPort === 'top' ? Math.min(sp.y, tp.y) : Math.max(sp.y, tp.y)) + dir * dynamicClear;
      const sx = tp.x > sp.x ? 1 : -1;
      segs.push(`V ${peakY-dir*r}`,`Q ${sp.x},${peakY} ${sp.x+sx*r},${peakY}`,`H ${tp.x-sx*r}`,`Q ${tp.x},${peakY} ${tp.x},${peakY-dir*r}`,`V ${tp.y}`);
    } else {
      // Horizontal U-shape: go left/right, vertical, back right/left
      const dir = srcPort === 'left' ? -1 : 1;
      const peakX = (srcPort === 'left' ? Math.min(sp.x, tp.x) : Math.max(sp.x, tp.x)) + dir * clearance;
      const sy = tp.y > sp.y ? 1 : -1;
      segs.push(`H ${peakX-dir*r}`,`Q ${peakX},${sp.y} ${peakX},${sp.y+sy*r}`,`V ${tp.y-sy*r}`,`Q ${peakX},${tp.y} ${peakX-dir*r},${tp.y}`,`H ${tp.x}`);
    }
    return segs.join(' ');
  }
  const horiz = srcPort === 'right' || srcPort === 'left';
  const parallel = (srcPort==='right'&&tgtPort==='left')||(srcPort==='left'&&tgtPort==='right')||(srcPort==='bottom'&&tgtPort==='top')||(srcPort==='top'&&tgtPort==='bottom');
  if (parallel && horiz) {
    const rawMidX = (sp.x + tp.x) / 2;
    const minClear = 50;
    const midX = sp.x < tp.x ? Math.max(rawMidX, sp.x + minClear) : Math.min(rawMidX, sp.x - minClear);
    const dy = tp.y - sp.y;
    if (Math.abs(dy) < 1) { segs.push(`H ${tp.x}`); }
    else {
      const sy = dy > 0 ? 1 : -1;
      const sx = tp.x > sp.x ? 1 : -1;
      segs.push(`H ${midX-sx*r}`,`Q ${midX},${sp.y} ${midX},${sp.y+sy*r}`,`V ${tp.y-sy*r}`,`Q ${midX},${tp.y} ${midX+sx*r},${tp.y}`,`H ${tp.x}`);
    }
  } else if (parallel && !horiz) {
    const rawMidY = (sp.y + tp.y) / 2;
    const minClearV = 50;
    const midY = sp.y < tp.y ? Math.max(rawMidY, sp.y + minClearV) : Math.min(rawMidY, sp.y - minClearV);
    const dx = tp.x - sp.x;
    if (Math.abs(dx) < 1) { segs.push(`V ${tp.y}`); }
    else {
      const sx = dx > 0 ? 1 : -1;
      const sy = tp.y > sp.y ? 1 : -1;
      segs.push(`V ${midY-sy*r}`,`Q ${sp.x},${midY} ${sp.x+sx*r},${midY}`,`H ${tp.x-sx*r}`,`Q ${tp.x},${midY} ${tp.x},${midY+sy*r}`,`V ${tp.y}`);
    }
  } else if (horiz) {
    const sy = tp.y > sp.y ? 1 : -1;
    const sx = tp.x > sp.x ? 1 : -1;
    if (Math.abs(tp.y - sp.y) > r * 2) { segs.push(`H ${tp.x-sx*r}`,`Q ${tp.x},${sp.y} ${tp.x},${sp.y+sy*r}`,`V ${tp.y}`); }
    else { segs.push(`H ${tp.x}`,`V ${tp.y}`); }
  } else {
    const sx = tp.x > sp.x ? 1 : -1;
    const sy = tp.y > sp.y ? 1 : -1;
    if (Math.abs(tp.x - sp.x) > r * 2) { segs.push(`V ${tp.y-sy*r}`,`Q ${sp.x},${tp.y} ${sp.x+sx*r},${tp.y}`,`H ${tp.x}`); }
    else { segs.push(`V ${tp.y}`,`H ${tp.x}`); }
  }
  return segs.join(' ');
}

function edgeLabelXY(srcPort, tgtPort, sp, tp) {
  // U-shape: label on the horizontal segment
  if (srcPort === tgtPort) {
    if (srcPort === 'top') return { x: (sp.x+tp.x)/2, y: Math.min(sp.y, tp.y) - 72 };
    if (srcPort === 'bottom') return { x: (sp.x+tp.x)/2, y: Math.max(sp.y, tp.y) + 72 };
    if (srcPort === 'left') return { x: Math.min(sp.x, tp.x) - 72, y: (sp.y+tp.y)/2 };
    return { x: Math.max(sp.x, tp.x) + 72, y: (sp.y+tp.y)/2 };
  }
  const horiz = srcPort === 'right' || srcPort === 'left';
  const parallel = (srcPort==='right'&&tgtPort==='left')||(srcPort==='left'&&tgtPort==='right')||(srcPort==='bottom'&&tgtPort==='top')||(srcPort==='top'&&tgtPort==='bottom');
  if (parallel && horiz) {
    if (Math.abs(tp.y - sp.y) < 1) return { x: (sp.x+tp.x)/2, y: sp.y-12 };
    return { x: (sp.x+tp.x)/2+12, y: (sp.y+tp.y)/2 };
  } else if (parallel && !horiz) {
    if (Math.abs(tp.x - sp.x) < 1) return { x: sp.x+12, y: (sp.y+tp.y)/2 };
    return { x: (sp.x+tp.x)/2, y: (sp.y+tp.y)/2-12 };
  } else if (horiz) {
    return Math.abs(tp.x-sp.x) >= Math.abs(tp.y-sp.y)
      ? { x: (sp.x+tp.x)/2, y: sp.y-12 }
      : { x: tp.x+12, y: (sp.y+tp.y)/2 };
  } else {
    return Math.abs(tp.y-sp.y) >= Math.abs(tp.x-sp.x)
      ? { x: sp.x+12, y: (sp.y+tp.y)/2 }
      : { x: (sp.x+tp.x)/2, y: tp.y-12 };
  }
}

