        clfLabel.setAttribute("x",legendX+padding);clfLabel.setAttribute("y",yOff);
        clfLabel.setAttribute("font-size","8");clfLabel.setAttribute("fill",T.tm);clfLabel.setAttribute("font-family","Consolas");clfLabel.setAttribute("letter-spacing","1");
