      metadata:{...metadata,lastUpdated:now},
      groups:groups.map(g=>({id:g.id,type:g.type,label:g.label,children:g.children||[],...(g.collapsed?{collapsed:true}:{}),...(g.compliance?{compliance:g.compliance}:{})})),
      nodes:nodes.map(n=>({id:n.id,type:n.type,label:n.label,techName:n.techName||""})),
