          {editMode&&hasData&&<div style={{padding:8,borderRadius:4,border:`1px solid ${T.sel}40`,background:theme==="dark"?"rgba(59,130,246,.04)":"rgba(59,130,246,.03)"}}><p style={{margin:0,fontSize:8,color:T.ts,lineHeight:1.5}}><b style={{color:T.sel}}>Edit</b> — Drag · Click node → Connect/Delete · Resize groups via corner handle</p></div>}
